from pathlib import Path
import re

p=Path('runtime-source.html')
s=p.read_text(encoding='utf-8')

def rep(old,new,label):
    global s
    n=s.count(old)
    if n!=1:
        raise SystemExit(f'{label}: expected 1 marker, found {n}')
    s=s.replace(old,new,1)

def line(pattern,new,label):
    global s
    s2,n=re.subn(pattern,new,s,count=1,flags=re.M)
    if n!=1:
        raise SystemExit(f'{label}: expected 1 line, found {n}')
    s=s2

