line(r'^if\(new URLSearchParams.*$', "if(new URLSearchParams(location.search).has('test'))window.__FP_TEST__={getState:()=>JSON.parse(JSON.stringify(state)),setActor:id=>{state.currentMemberId=id;save()},setTrashEnabled:v=>{state.config.trashRetentionEnabled=!!v;save()},createCategory:(k,n)=>createCategory(k,n),renameCategory,deleteCategory,mergeCategory,toggleQuickCategory,createOperation:data=>{const t=now(),o={id:data.id||uid('op'),kind:data.kind||'expense',amount:Number(data.amount),categoryId:data.categoryId,walletId:data.walletId||state.activeWalletId,note:data.note||'',occurredAt:data.occurredAt||t,createdByMemberId:state.currentMemberId,createdAt:t,lastEditedByMemberId:state.currentMemberId,lastEditedAt:t,revisions:[],status:'active',deletedAt:null,deletedByMemberId:null,trashExpiresAt:null,receipt:null,links:{},transferGroupId:null};state.operations.push(o);save();renderAll();return o.id},editOperation:(id,changes)=>{const o=state.operations.find(x=>x.id===id),actual=Object.entries(changes).filter(([field,value])=>!sameMeaning(field,o[field],value)).map(([field,newValue])=>({field,oldValue:o[field],newValue}));if(actual.length){revisionBatch(o,actual,'user');for(const c of actual)o[c.field]=c.newValue;o.lastEditedByMemberId=state.currentMemberId;o.lastEditedAt=now()}save();renderAll()},trashOperation:id=>{const o=state.operations.find(x=>x.id===id);revision(o,'status','active','trash');o.status='trash';o.deletedAt=now();o.deletedByMemberId=state.currentMemberId;o.trashExpiresAt=o.deletedAt+45*86400000;o.lastEditedByMemberId=state.currentMemberId;o.lastEditedAt=o.deletedAt;save();renderAll()},setTrashExpiry:(id,value)=>{const o=state.operations.find(x=>x.id===id);if(o){o.trashExpiresAt=value;save()}},restoreOperation,permanentDelete:id=>{state.operations=state.operations.filter(o=>o.id!==id);save();renderAll()},filteredOperations:()=>filteredOperations().map(o=>o.id),analyticsFilteredOperations:()=>analyticsFilteredOperations().map(o=>o.id),setTypeFilter:v=>{opsTypeFilter=v;renderOperations()},setCategoryFilter:ids=>{selectedCategoryIds=new Set(ids);renderOperations()},setAmountFilter:(min,max)=>{amountMin=min??null;amountMax=max??null;renderOperations()},resetOperationFilters:()=>{opsTypeFilter='all';selectedCategoryIds.clear();amountMin=null;amountMax=null;renderOperations()},setAnalyticsMode:v=>{analyticsMode=v;renderAnalytics()},setAnalyticsCategories:ids=>{analyticsSelectedCategoryIds=new Set(ids);renderAnalytics()},setAnalyticsSearch:v=>{analyticsSearch=v;renderAnalytics()},setAnalyticsSort:v=>{analyticsSort=v;renderAnalytics()},revisionChanges,renderAll};",'test api')

